-- ملء محتوى عنقود "السيرة النبوية" (seerah-nabawiyya) — أربعة تصنيفات
-- فرعية متبقية draft (استنفاد الجزء الأخير من العنقود): الشمائل
-- المحمدية، الأخلاق النبوية، دلائل النبوة، فقه السيرة والدروس
-- التربوية.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب دروس alaqat-dawliyya/qada-dawa-ithbat
-- (تعريفي موجز: قسم body + قسم examples).
-- المصادر المعتمدة: الشمائل المحمدية للترمذي (شمائل)، الشفا بتعريف
-- حقوق المصطفى للقاضي عياض (أخلاق نبوية)، دلائل النبوة ومعرفة أحوال
-- صاحب الشريعة للبيهقي (دلائل النبوة)، فقه السيرة النبوية لمحمد سعيد
-- رمضان البوطي (فقه السيرة).
-- أربعة أحاديث استُشهد بها، تحقَّقت حرفياً عبر WebSearch قبل الإدراج:
-- وصف البراء بن عازب لهيئة النبي صلى الله عليه وسلم (متفق عليه، رواه
-- البخاري 3551 ومسلم 2337)، «كان خُلُق نبي الله القرآن» عن عائشة (رواه
-- مسلم 746)، انشقاق القمر عن ابن مسعود (متفق عليه، رواه البخاري 4864
-- ومسلم 2802)، حديث بعث معاذ بن جبل إلى اليمن والتدرج في الدعوة
-- (متفق عليه، رواه البخاري 1458 ومسلم 19).
-- ثلاث آيات تحقَّقت حرفياً محلياً من artifacts/majalis/public/data/quran
-- عبر حقل numberInSurah: القلم 4 (وإنك لعلى خلق عظيم)، القمر 1
-- (اقتربت الساعة وانشق القمر)، الأحزاب 21 (لقد كان لكم في رسول الله
-- أسوة حسنة).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الأربعة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) الشمائل المحمدية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='b2e14ce4-cfdd-4e7d-9be9-65505cf29617' AND title='الشمائل المحمدية: صفة النبي صلى الله عليه وسلم الخَلقية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الشمائل المحمدية: صفة النبي صلى الله عليه وسلم الخَلقية', 'تعريف موجز بعلم الشمائل النبوية ووصف هيئة النبي صلى الله عليه وسلم الخَلقية كما وصفها الصحابة', 'b2e14ce4-cfdd-4e7d-9be9-65505cf29617', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الشمائل علم مستقل يصف هيئة النبي صلى الله عليه وسلم وعاداته', 'تعريف الشمائل كعلم مستقل ضمن السيرة يُعنى بوصف هيئة النبي صلى الله عليه وسلم الخَلقية وأخلاقه وعاداته اليومية (مأكله ومشربه وملبسه ونومه وضحكه)، تمييزًا عن كتب السيرة العامة التي تُعنى بترتيب الأحداث والغزوات. وأشهر من صنّف في هذا الباب الإمام أبو عيسى الترمذي في كتابه المتخصص "الشمائل المحمدية"، الذي جمع فيه ما ورد عن الصحابة من وصف دقيق لهيئة النبي صلى الله عليه وسلم، معتمدًا على روايات أصحابه الذين لازموه وشاهدوه عن قرب كالبراء بن عازب وأنس بن مالك وعلي بن أبي طالب. والغاية من هذا العلم ليست مجرد التوثيق التاريخي، بل استحضار هيئة النبي صلى الله عليه وسلم في القلب تعظيمًا ومحبةً واقتداءً، فوصفه الظاهر كان معبّرًا عن كمال خَلقه كما كان خُلُقه معبرًا عن كمال دينه.', 1),
    (v_lesson, 'examples', 'وصف البراء بن عازب لهيئة النبي صلى الله عليه وسلم', 'عن البراء بن عازب رضي الله عنه قال: «كان رسول الله صلى الله عليه وسلم رجلًا مربوعًا، بعيد ما بين المنكبين، عظيم الجُمّة إلى شحمة أذنيه، عليه حُلّة حمراء، ما رأيت شيئًا قط أحسن منه» (متفق عليه، رواه البخاري 3551 ومسلم 2337). وهذا الوصف الدقيق من صحابي عاصره ورآه مرارًا نموذج لما دوّنه علماء الشمائل من تفاصيل هيئته الخَلقية: اعتدال قامته، وعرض منكبيه، وكثافة شعره الممتد إلى شحمة أذنيه، وحسن هيئته العامة التي كانت تأخذ بالأبصار قبل أن تسمع الآذان كلامه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الشمائل المحمدية — أبو عيسى محمد بن عيسى الترمذي', 1);
  END IF;

  -- 2) الأخلاق النبوية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='9ec2eb4f-a5ab-4549-b181-f1f348d70d6e' AND title='الأخلاق النبوية: خُلُقه صلى الله عليه وسلم القرآن') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الأخلاق النبوية: خُلُقه صلى الله عليه وسلم القرآن', 'تعريف موجز بمنزلة الأخلاق النبوية وكون خُلُق النبي صلى الله عليه وسلم ترجمة عملية لأخلاق القرآن', '9ec2eb4f-a5ab-4549-b181-f1f348d70d6e', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الأخلاق النبوية ترجمة عملية لأخلاق القرآن', 'الأخلاق النبوية هي الجانب الباطن المكمّل لما وصفه علماء الشمائل من هيئته الظاهرة، وهي محل عناية خاصة عند علماء السيرة والأخلاق، ومن أوسع من جمعها القاضي عياض في كتابه "الشفا بتعريف حقوق المصطفى" في الباب الذي عقده لمكارم أخلاقه وشمائله الباطنة. وقد بلغ النبي صلى الله عليه وسلم في مكارم الأخلاق ما لم يبلغه غيره، فجمع بين الحلم والرحمة والعدل والتواضع وحسن العشرة، حتى شهد له القرآن نفسه بذلك في قوله تعالى ﴿وَإِنَّكَ لَعَلَىٰ خُلُقٍ عَظِيمٍ﴾، وكان صلى الله عليه وسلم يطبّق عمليًا كل ما دعا إليه القرآن من مكارم الأخلاق قبل أن يأمر به غيره، حتى غدا خُلُقه بمجموعه ترجمة حيّة لتعاليم القرآن الخُلقية، لا مجرد التزام ببعضها.', 1),
    (v_lesson, 'examples', 'شهادة القرآن بعظمة خُلُقه وشهادة عائشة بأن خُلُقه كان القرآن', 'قال تعالى: ﴿وَإِنَّكَ لَعَلَىٰ خُلُقٍ عَظِيمٍ﴾ (القلم: 4)، وهي شهادة إلهية مباشرة بعظمة خُلُقه صلى الله عليه وسلم. وعن سعد بن هشام بن عامر أنه سأل عائشة رضي الله عنها عن خُلُق رسول الله صلى الله عليه وسلم، فقالت: «ألست تقرأ القرآن؟» قال: بلى، قالت: «فإن خُلُق نبي الله صلى الله عليه وسلم كان القرآن» (رواه مسلم 746)، فبيّنت رضي الله عنها أن خُلُقه صلى الله عليه وسلم لم يكن منفصلًا عن تعاليم القرآن، بل كان تجسيدًا عمليًا شاملًا لها في تعامله وعبادته وسائر أحواله.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الشفا بتعريف حقوق المصطفى — القاضي عياض بن موسى اليحصبي', 1);
  END IF;

  -- 3) دلائل النبوة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='98b4b3a6-78a9-4fdd-bc17-da29eb906895' AND title='دلائل النبوة: انشقاق القمر أنموذجًا لمعجزاته الحسية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('دلائل النبوة: انشقاق القمر أنموذجًا لمعجزاته الحسية', 'تعريف موجز بعلم دلائل النبوة ومعجزة انشقاق القمر أنموذجًا للمعجزات الحسية المتواترة', '98b4b3a6-78a9-4fdd-bc17-da29eb906895', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'دلائل النبوة علم إثبات صدق النبوة، وانشقاق القمر أعظم معجزاته الحسية', 'دلائل النبوة علم مستقل يُعنى بجمع الأدلة والبراهين التي تثبت صدق نبوة محمد صلى الله عليه وسلم، ومنها المعجزات الحسية الخارقة للعادة التي أجراها الله على يديه تأييدًا له، إلى جانب دلائل أخرى كإخباره عن الغيب وشهادة الكتب السابقة وكمال شريعته. ومن أشهر من صنّف في هذا الباب الإمام أحمد بن الحسين البيهقي في موسوعته "دلائل النبوة ومعرفة أحوال صاحب الشريعة"، التي استوعبت أبرز ما نُقل من معجزاته صلى الله عليه وسلم بالأسانيد. ومن أعظم هذه المعجزات الحسية وأشهرها ثبوتًا معجزة انشقاق القمر، التي وقعت بمكة قبل الهجرة حين سأل مشركو قريش النبي صلى الله عليه وسلم آية، فانشق القمر فلقتين رآهما الناس، وهي معجزة نصّ عليها القرآن صراحة وتواترت أخبارها عن جمع من الصحابة، مما جعلها من أقوى الأدلة الحسية على صدق نبوته.', 1),
    (v_lesson, 'examples', 'التسجيل القرآني لانشقاق القمر وشهادة ابن مسعود على وقوعه', 'قال تعالى: ﴿اقْتَرَبَتِ السَّاعَةُ وَانشَقَّ الْقَمَرُ﴾ (القمر: 1)، وهو تسجيل قرآني معاصر لوقوع هذه المعجزة. وعن عبد الله بن مسعود رضي الله عنه قال: «انشقّ القمر على عهد رسول الله صلى الله عليه وسلم فرقتين، فرقة فوق الجبل وفرقة دونه، فقال رسول الله صلى الله عليه وسلم: اشهدوا» (متفق عليه، رواه البخاري 4864 ومسلم 2802)، وهذا نص صريح من صحابي شاهد الحادثة بنفسه، أُمر بالإشهاد عليها توثيقًا لهذه المعجزة الحسية الظاهرة أمام الناس.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'دلائل النبوة ومعرفة أحوال صاحب الشريعة — أحمد بن الحسين البيهقي', 1);
  END IF;

  -- 4) فقه السيرة والدروس التربوية
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='fa61c9d5-2806-48ed-a1d8-aba64af919d8' AND title='فقه السيرة: التدرج منهجًا تربويًا مستنبطًا من هدي النبي صلى الله عليه وسلم') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('فقه السيرة: التدرج منهجًا تربويًا مستنبطًا من هدي النبي صلى الله عليه وسلم', 'تعريف موجز بعلم فقه السيرة واستنباط مبدأ التدرج التربوي من هدي النبي صلى الله عليه وسلم في التعليم والدعوة', 'fa61c9d5-2806-48ed-a1d8-aba64af919d8', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'فقه السيرة يستنبط الدروس التربوية من وقائعها، ومبدأ التدرج أنموذجًا', 'فقه السيرة علم يتجاوز مجرد سرد وقائع السيرة النبوية زمنيًا إلى استنباط الأحكام والدروس التربوية والدعوية من أحداثها ووقائعها، وهو ما ميّزه محمد سعيد رمضان البوطي في كتابه المتخصص "فقه السيرة النبوية" عن كتب السيرة التقليدية بجعله السيرة مصدرًا لاستنباط منهج عملي في الدعوة والتربية والقيادة، لا مجرد محل رواية تاريخية. ومن أبرز المبادئ التربوية المستنبطة من السيرة مبدأ التدرج، وهو تقديم الأهم فالمهم في التعليم والدعوة، والبدء بالأصول العظام قبل الفروع، ومراعاة استعداد المدعو وحاله. وقد طبّق النبي صلى الله عليه وسلم هذا المبدأ عمليًا في توجيهاته لدعاته ومعلّميه، فكان يوصيهم بالبدء بالتوحيد والشهادتين قبل الانتقال إلى الفرائض العملية كالصلاة والزكاة، تحقيقًا لبناء الإيمان أولًا قبل تكليف الجوارح.', 1),
    (v_lesson, 'examples', 'الأسوة الحسنة أصل قرآني جامع، ووصية النبي لمعاذ في اليمن تطبيق عملي للتدرج', 'قال تعالى: ﴿لَّقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ﴾ (الأحزاب: 21)، وهي الأصل القرآني الجامع في وجوب اتخاذ هديه صلى الله عليه وسلم قدوة عملية في كل شؤون الحياة، ومنها منهجه التربوي والدعوي. وعن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم لما بعث معاذ بن جبل إلى اليمن قال له: «إنك تأتي قومًا من أهل الكتاب، فادعهم إلى شهادة أن لا إله إلا الله وأني رسول الله، فإن هم أطاعوا لذلك فأعلمهم أن الله افترض عليهم خمس صلوات في كل يوم وليلة...» (متفق عليه، رواه البخاري 1458 ومسلم 19)، وهذا نص صريح في تعليم النبي صلى الله عليه وسلم أصل التدرج: البدء بالتوحيد، ثم الصلاة، ثم الزكاة، ترتيبًا للأهم فالمهم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فقه السيرة النبوية — محمد سعيد رمضان البوطي', 1);
  END IF;

  -- تحديث حالة التصنيفات الأربعة إلى منشور بعد اكتمال محتواها
  UPDATE categories SET status='published'
  WHERE id IN (
    'b2e14ce4-cfdd-4e7d-9be9-65505cf29617', '9ec2eb4f-a5ab-4549-b181-f1f348d70d6e',
    '98b4b3a6-78a9-4fdd-bc17-da29eb906895', 'fa61c9d5-2806-48ed-a1d8-aba64af919d8'
  );
END $$;
